        M.setBehindDistance(Value)
        if M.getTeleporting() and M.getCurrentTarget() then
            M.anchorToPlayer(M.getCurrentTarget())
        end
    end,
})
MainPlayer:AddButton({
    Text = "Следующая цель",
    Func = function()
        if M.getTeleporting() then
            local validPlayers = M.getValidPlayers()
            if #validPlayers > 0 then
                local target = M.getNextTarget()
                M.setCurrentTarget(target)
                if target then
                    M.anchorToPlayer(target)
                end
            end
        end
    end,
})

